// Parse all sources: RSS feeds, Google Trends, Reddit
const items = $input.all();
const signals = [];

for (const item of items) {
  const raw = item.json;

  // ── RSS XML feeds ──
  if (typeof raw.data === 'string' || typeof raw.body === 'string') {
    const text = raw.data || raw.body || '';
    const blocks = text.match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];
    for (const block of blocks.slice(0, 8)) {
      const title = (block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i) || [])[1]?.trim();
      const desc  = (block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/is) || [])[1]?.replace(/<[^>]+>/g,'').trim().substring(0,200);
      const link  = (block.match(/<link>([^<]+)<\/link>/i) || [])[1]?.trim();
      if (title && title.length > 15 && !title.toLowerCase().includes('advertisement')) {
        signals.push({ type: 'rss', title, summary: desc || '', link: link || '', weight: 1 });
      }
    }
  }

  // ── Google Trends ──
  if (raw.interest_over_time || raw.related_queries) {
    const trending = (raw.related_queries || []).flatMap(q => (q.rising || []).slice(0, 3));
    for (const t of trending) {
      signals.push({ type: 'trend', title: t.query || '', summary: `Trending search: ${t.query} (rising ${t.value})`, link: '', weight: 2 });
    }
  }

  // ── Reddit ──
  if (raw.data?.children) {
    for (const post of raw.data.children.slice(0, 10)) {
      const p = post.data;
      if (p.score > 50 && p.title) {
        signals.push({ type: 'reddit', title: p.title, summary: p.selftext?.substring(0,200) || `${p.score} upvotes · ${p.num_comments} comments`, link: `https://reddit.com${p.permalink}`, weight: 1.5 });
      }
    }
  }
}

// Deduplicate by first 40 chars of title
const seen = new Set();
const unique = signals.filter(s => {
  const key = s.title.substring(0,40).toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

console.log(`Parsed ${unique.length} signals from ${items.length} sources`);
return [{ json: { signals: unique.slice(0,30), scrapedAt: new Date().toISOString() } }];

