const response = $input.first().json;
const content = response.content?.[0]?.text || '';
if (!content) throw new Error('Claude returned empty response. Check API key.');

const topics = [];
for (let i = 1; i <= 5; i++) {
  const title = (content.match(new RegExp(`TOPIC_${i}:\\s*(.+)`)) || [])[1]?.trim();
  const why   = (content.match(new RegExp(`WHY_${i}:\\s*(.+)`)) || [])[1]?.trim();
  const angle = (content.match(new RegExp(`ANGLE_${i}:\\s*(.+)`)) || [])[1]?.trim();
  if (title) topics.push({ rank: i, title, why: why || '', angle: angle || '', generatedAt: new Date().toISOString() });
}

if (topics.length === 0) throw new Error('Could not parse topics from Claude response: ' + content.substring(0,200));
console.log(`Extracted ${topics.length} topics for this week`);
return topics.map(t => ({ json: t }));

const claudeResponse = $input.first().json;
const topic = $('Process Each Topic (Loop)').first().json;
const content = claudeResponse.content?.[0]?.text || '';
if (!content) throw new Error('Claude draft response was empty');

function extractSection(text, start, end) {
  const s = text.indexOf(start);
  if (s === -1) return '';
  const from = s + start.length;
  const to = end ? text.indexOf(end, from) : text.length;
  return text.substring(from, to === -1 ? text.length : to).trim();
}

const linkedin        = extractSection(content, '---LINKEDIN---',          '---INSTAGRAM_CAPTION---');
const instagram       = extractSection(content, '---INSTAGRAM_CAPTION---', '---CAROUSEL_SLIDES---');
const carouselRaw     = extractSection(content, '---CAROUSEL_SLIDES---',   '---YOUTUBE_SHORTS---');
const youtubeScript   = extractSection(content, '---YOUTUBE_SHORTS---',    '---IMAGE_PROMPT---');
const imagePrompt     = extractSection(content, '---IMAGE_PROMPT---',       null);

// Parse carousel slides into array
const slides = [];
for (let i = 1; i <= 5; i++) {
  const match = carouselRaw.match(new RegExp(`Slide${i}:\\s*(.+)`));
  if (match) slides.push(match[1].trim());
}

console.log(`Parsed all formats for: ${topic.title} | Carousel: ${slides.length} slides`);

return [{
  json: {
    topic_rank:        topic.rank,
    topic_title:       topic.title,
    topic_why:         topic.why,
    topic_angle:       topic.angle,
    linkedin_draft:    linkedin,
    instagram_draft:   instagram,
    carousel_slides:   slides,
    carousel_raw:      carouselRaw,
    youtube_script:    youtubeScript,
    image_prompt:      imagePrompt,
    week_of:           new Date().toISOString().split('T')[0],
    drafted_at:        new Date().toISOString()
  }
}];

